.meta{margin-top:7px;color:var(--_muted);font-size:13px;line-height:1.45}
.winner-callout{display:flex;align-items:center;justify-content:space-between;gap:16px;padding:14px 24px;border-bottom:1px solid var(--_line);background:var(--_accent-soft)}
.winner-copy{display:flex;align-items:center;gap:10px;min-width:0;color:var(--_text);font-size:14px}
.mark{display:inline-flex;flex:0 0 auto;min-width:28px;height:28px;align-items:center;justify-content:center;border-radius:999px;background:color-mix(in srgb,var(--_ok) 12%,var(--_bg));color:var(--_ok);font-size:16px;font-weight:850}
.winner-name{font-weight:800}
.winner-score{flex:0 0 auto;color:var(--_accent);font-size:16px;font-weight:850;font-variant-numeric:tabular-nums}
.scroll{max-height:640px;overflow:auto;overscroll-behavior:contain;scrollbar-color:var(--_line) transparent}
table{width:100%;min-width:max-content;border-collapse:separate;border-spacing:0;font-size:14px;line-height:1.35}
caption{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0}
th,td{min-width:150px;padding:14px 18px;border-right:1px solid var(--_line);border-bottom:1px solid var(--_line);background:var(--_bg);text-align:center;vertical-align:middle;font-variant-numeric:tabular-nums}
th:last-child,td:last-child{border-right:0}
thead th{position:sticky;top:0;z-index:3;padding-top:16px;padding-bottom:16px;background:var(--_raised);box-shadow:0 1px 0 var(--_line)}
.corner{left:0;z-index:5;min-width:220px;color:var(--_muted);font-size:11px;font-weight:800;letter-spacing:.08em;text-align:left;text-transform:uppercase}
.option{min-width:164px;color:var(--_text);font-size:14px;font-weight:750}
.option-name{display:block}
.option.winner,.total.winner{background:var(--_accent-soft);box-shadow:inset 0 3px 0 var(--_accent)}
.option-note{display:block;max-width:190px;margin:5px auto 0;color:var(--_muted);font-size:11px;font-weight:500;line-height:1.35}
.ribbon{display:inline-flex;margin-bottom:7px;padding:3px 8px;border-radius:999px;background:var(--_accent);color:#fff;font-size:9px;font-weight:850;letter-spacing:.08em;text-transform:uppercase}
.criterion{position:sticky;left:0;z-index:2;min-width:220px;max-width:280px;background:var(--_raised);color:var(--_text);font-weight:700;text-align:left;box-shadow:1px 0 0 var(--_line)}
.criterion small{display:block;margin-top:4px;color:var(--_muted);font-size:11px;font-weight:600}
.heat{font-weight:800}
.heat small{display:block;margin-top:3px;color:var(--_muted);font-size:10px;font-weight:650}
tbody tr:hover th{background:var(--_hover)}
tbody tr:hover td{outline:2px solid color-mix(in srgb,var(--_accent) 18%,transparent);outline-offset:-2px}
tfoot th,tfoot td{position:sticky;bottom:0;z-index:3;border-bottom:0;background:var(--_raised);box-shadow:0 -1px 0 var(--_line);font-weight:850}
tfoot th{left:0;z-index:4;text-align:left}
.total{font-size:16px}
.formula{padding:12px 24px;color:var(--_muted);font-size:11px;line-height:1.45;background:var(--_soft)}
.empty{padding:42px 24px;color:var(--_muted);font-size:14px;text-align:center}
@media (max-width:520px){.heading{padding:18px 18px 16px}.winner-callout{align-items:flex-start;padding:13px 18px}th,td{padding:12px 14px;min-width:140px}.criterion,.corner{min-width:180px;max-width:210px}}

@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_group:#182235;--_accent-soft:#1b2145;--_hover:#172033}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];

const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Decision matrix';
const options=Array.isArray(data.options)?data.options:[];
const criteria=Array.isArray(data.criteria)?data.criteria:[];
const scores=Array.isArray(data.scores)?data.scores:[];
const weights=criteria.map((item) => item&&Number.isFinite(Number(item.weight))?Math.max(0,Number(item.weight)):0);
const totalWeight=weights.reduce((sum,value)=>sum+value,0);
const normalized = (optionIndex,criterionIndex) => {
  const row=Array.isArray(scores[optionIndex])?scores[optionIndex]:[];
  const raw=Number(row[criterionIndex]);
  const max=criteria[criterionIndex]&&Number(criteria[criterionIndex].maxScore)>0?Number(criteria[criterionIndex].maxScore):5;
  return Number.isFinite(raw)?Math.max(0,Math.min(max,raw))/max:0;
};
const totals=options.map((_,optionIndex) => totalWeight?criteria.reduce((sum,__,criterionIndex)=>sum+normalized(optionIndex,criterionIndex)*weights[criterionIndex],0)/totalWeight*100:0);
let winnerIndex=-1;
totals.forEach((value,index)=>{ if(winnerIndex<0||value>totals[winnerIndex]) winnerIndex=index; });
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading');
heading.appendChild(make('div','eyebrow','Weighted decision'));
heading.appendChild(make('h2','',title));
const description=typeof data.description==='string'&&data.description.trim()?data.description.trim():options.length+' options · '+criteria.length+' weighted criteria';
heading.appendChild(make('div','meta',description));
frame.appendChild(heading);
if(!options.length||!criteria.length||!totalWeight){
  frame.appendChild(make('div','empty','Add options, criteria, positive weights, and scores to build the matrix.'));
}else{
  const callout=make('div','winner-callout');
  const copy=make('div','winner-copy'); const mark=make('span','mark','✓'); mark.setAttribute('aria-hidden','true'); copy.appendChild(mark);
  copy.appendChild(make('span','', 'Top choice '));
  copy.appendChild(make('span','winner-name',options[winnerIndex]&&options[winnerIndex].name!=null?String(options[winnerIndex].name):'Untitled'));
  callout.appendChild(copy); callout.appendChild(make('div','winner-score',totals[winnerIndex].toFixed(1)+' / 100')); frame.appendChild(callout);
  const scroll=make('div','scroll'); const table=make('table'); table.appendChild(make('caption','',title));
  const thead=make('thead'); const headRow=make('tr'); const corner=make('th','corner','Criteria · weight'); corner.scope='col'; headRow.appendChild(corner);
  options.forEach((option,index)=>{
    const th=make('th','option'+(index===winnerIndex?' winner':'')); th.scope='col';
    if(index===winnerIndex) th.appendChild(make('span','ribbon','Winner'));
    th.appendChild(make('span','option-name',option&&option.name!=null?String(option.name):'Untitled'));
    if(option&&option.note) th.appendChild(make('span','option-note',String(option.note)));
    headRow.appendChild(th);
  });
  thead.appendChild(headRow); table.appendChild(thead);
  const tbody=make('tbody');
  criteria.forEach((criterion,criterionIndex)=>{
    const row=make('tr'); const max=criterion&&Number(criterion.maxScore)>0?Number(criterion.maxScore):5;
    const label=make('th','criterion',criterion&&criterion.label!=null?String(criterion.label):'Untitled criterion'); label.scope='row';
    label.appendChild(make('small','',weights[criterionIndex]+' weight · max '+max)); row.appendChild(label);
    options.forEach((_,optionIndex)=>{
      const source=Array.isArray(scores[optionIndex])?scores[optionIndex][criterionIndex]:undefined;
      const raw=Number(source); const valid=Number.isFinite(raw); const ratio=normalized(optionIndex,criterionIndex);
      const tone=ratio>=.75?'var(--_ok)':ratio>=.45?'var(--_partial)':'var(--_no)';
      const td=make('td','heat',valid?String(Math.max(0,Math.min(max,raw))):'—');
      td.style.background='color-mix(in srgb,'+tone+' '+(8+Math.round(ratio*12))+'%,var(--_bg))';
      if(valid) td.appendChild(make('small','',Math.round(ratio*100)+'%'));
      row.appendChild(td);
    });
    tbody.appendChild(row);
  });
  table.appendChild(tbody);
  const tfoot=make('tfoot'); const totalRow=make('tr'); const totalLabel=make('th','criterion','Weighted total'); totalLabel.scope='row'; totalRow.appendChild(totalLabel);
  totals.forEach((value,index)=>totalRow.appendChild(make('td','total'+(index===winnerIndex?' winner':''),value.toFixed(1))));
  tfoot.appendChild(totalRow); table.appendChild(tfoot); scroll.appendChild(table); frame.appendChild(scroll);
  frame.appendChild(make('div','formula','Total = Σ(score ÷ criterion max × weight) ÷ Σ(weights) × 100. Missing or invalid scores contribute zero.'));
}
root.appendChild(frame);
parent.appendChild(host);
